use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Serialize, Deserialize)]
struct UserProfile {
    user_id: u64,
    username: String,
}

#[derive(Debug, Serialize, Deserialize)]
struct TaskRecord {
    task_id: u32,
    description: String,
    is_completed: bool,
}

trait ApiObject {
    fn get_identifier(&self) -> Box<dyn std::any::Any + Send + Sync>;
    fn to_string_representation(&self) -> String;
}
impl ApiObject for UserProfile {
    fn get_identifier(&self) -> Box<dyn std::any::Any + Send + Sync> {
        Box::new(self.user_id)
    }
    fn to_string_representation(&self) -> String {
        format!("User: {}", self.username)
    }
}
impl ApiObject for TaskRecord {
    fn get_identifier(&self) -> Box<dyn std::any::Any + Send + Sync> {
        Box::new(self.task_id)
    }
    fn to_string_representation(&self) -> String {
        format!("Task ID: {}", self.task_id)
    }
}

fn process_generic_objects<T: ApiObject + 'static>(object: &T) -> String {
    let id = object.get_identifier();
    let representation = object.to_string_representation();
    format!("Processed Object - ID Type {:?}, Representation: {}", std::any::type_name::<T>(), representation)
}

