use std::fmt::{self, Display};
use serde::{Serialize, Deserialize};
use std::collections::HashMap;

trait JsonSerializable {
    fn serialize_to_map(&self) -> Result<HashMap<String, String>, String>;
}

struct TaskManagerPayload {
    user_id: u32,
    task_name: String,
    due_date: String,
}

impl JsonSerializable for TaskManagerPayload {
    fn serialize_to_map(&self) -> Result<HashMap<String, String>, String> {
        let mut map = HashMap::new();
        map.insert("user_id".to_string(), self.user_id.to_string());
        map.insert("task_name".to_string(), self.task_name.clone());
        map.insert("due_date".to_string(), self.due_date.clone());
        Ok(map)
    }
}

fn process_generic_data<T: JsonSerializable>(data: &T) -> Result<HashMap<String, String>, String> {
    data.serialize_to_map()
}

fn main() {
    let task = TaskManagerPayload {
        user_id: 101,
        task_name: String::from("Write API spec"),
        due_date: String::from("2024-12-31"),
    };

    match process_generic_data(&task) {
        Ok(payload) => {
            println!("Successfully processed payload:");
            for (key, value) in payload {
                println!("  {}: {}", key, value);
            }
        }
        Err(e) => {
            eprintln!("Failed to process data: {}", e);
        }
    }
}

use std::collections::HashMap;

struct MetadataContainer<const K: usize> {
    data: HashMap<usize, String>,
}

impl<const K: usize> MetadataContainer<K> {
    fn new() -> Self {
        MetadataContainer { data: HashMap::new() }
    }

    fn set_metadata(&mut self, key_id: usize, value: impl Into<String>) {
        self.data.insert(key_id, value.into());
    }

    fn get_size(&self, key_id: usize) -> Option<&str> {
        self.data.get(&key_id).map(|s| s.as_str())
    }

    fn print_summary(&self) {
        println!("--- Metadata Summary ---");
        for (key, value) in &self.data {
            println!("Key {}: {}", key, value);
        }
        println!("------------------------");
    }
}

fn main() {
    let mut layer_meta: MetadataContainer<1> = MetadataContainer::new();
