        println!("Successfully retrieved hash: {}", hash);
    }

    layer_meta.print_summary();
}

use std::collections::{VecDeque, HashMap, HashSet};

struct Graph<T> {
    adjacency_list: HashMap<T, Vec<T>>
}

impl<T: Eq + std::hash::Hash + Clone + std::fmt::Debug> Graph<T> {
    fn new() -> Self {
        Graph { adjacency_list: HashMap::new() }
    }

    fn add_edge(&mut self, u: T, v: T) {
        self.adjacency_list.entry(u.clone()).or_insert_with(Vec::new).push(v.clone());
        self.adjacency_list.entry(v).or_insert_with(Vec::new).push(u.clone());
    }

    fn bfs(&self, start_node: &T) -> Vec<T> {
        if !self.adjacency_list.contains_key(start_node) {
            return Vec::new();
        }

        let mut queue: VecDeque<T> = VecDeque::from(vec![start_node.clone()]);
        let mut visited: HashSet<T> = HashSet::new();
        let mut result: Vec<T> = Vec::new();

        visited.insert(start_node.clone());

        while let Some(current) = queue.pop_front() {
            result.push(current.clone());
            if let Some(neighbors) = self.adjacency_list.get(&current) {
                for neighbor in neighbors.iter() {
                    if !visited.contains(neighbor) {
                        visited.insert(neighbor.clone());
                        queue.push_back(neighbor.clone());
                    }
                }
            }
        }
        result
    }
}

use std::fs;
use std::path::{Path, PathBuf};
use std::io;

fn recursive_find(current_path: &PathBuf) -> io::Result<Vec<PathBuf>> {
    let mut found_paths = Vec::new();
    if !current_path.exists() {
        return Ok(found_paths);
    }

    let entries = fs::read_dir(current_path)?;
    for entry in entries {
        let entry = match entry {
            Ok(e) => e,
            Err(e) => {
                println!("Could not read directory entry: {}", e);
                continue;
            }
        };

        let path = entry.path();
        if path.is_dir() {
            match recursive_find(&path)? {
                nested_paths => found_paths.extend(nested_paths),
            }
        } else if path.is_file() {
            found_paths.push(path);
        }
    }

    Ok(found_paths)
}

#[tokio::main]
async fn main() -> io::Result<()> {
    let start_dir = PathBuf::from("./src"); 
    if !start_dir.exists() {
        println!("Please ensure a directory named 'src' exists relative to where you run this.");
        return Ok(());
    }

    match recursive_find(&start_dir)? {
        paths => {
            println!("Successfully found {} items.", paths.len());
            for path in paths {
                println!("Found: {}", path.display());
            }
        }
    }

    Ok(())
}

